// ─── Request Router & Validator ───────────────────────────────────────────
const raw = $input.first().json.body ?? $input.first().json;

const action        = String(raw.action || 'analyze_image').toLowerCase();
const image_url     = String(raw.image_url    || '').trim();
const image_base64  = String(raw.image_base64 || '').trim();
const image_type    = String(raw.image_type   || 'image/jpeg').trim();
const request_id    = 'req_' + Date.now();
const timestamp     = new Date().toISOString();

// Inventory push fields
const inventory     = raw.inventory     || [];    // Array of equipment rows (edited by user)
const cabinet_name  = String(raw.cabinet_name  || '').trim();
const location_name = String(raw.location_name || '').trim();
const u_height      = parseInt(raw.u_height || 42, 10);
const session_id    = String(raw.session_id || 'sess_' + Date.now());

const is_upload = image_base64.length > 100;
const has_image = is_upload || image_url.startsWith('http');

// Validate action-specific requirements
if (action === 'analyze_image' && !has_image) {
  return {
    action, error: 'Missing image: provide image_url or image_base64',
    request_id, timestamp
  };
}
if (action === 'push_to_dctrack') {
  if (!cabinet_name)  return { action, error: 'Missing cabinet_name', request_id, timestamp };
  if (!location_name) return { action, error: 'Missing location_name', request_id, timestamp };
  if (!Array.isArray(inventory) || inventory.length === 0)
    return { action, error: 'Missing or empty inventory array', request_id, timestamp };
}

return {
  action, image_url, image_base64, image_type,
  inventory, cabinet_name, location_name, u_height,
  request_id, session_id, timestamp, is_upload, has_image
};

// ─── Build Anthropic Vision API Body ─────────────────────────────────────
const d = $input.first().json;

const VISION_PROMPT = `You are a data center rack equipment scanner. Analyze this rack cabinet photo carefully and extract ALL visible equipment.

Return ONLY a valid JSON array (no markdown fences, no explanation text, no preamble). Each element must have EXACTLY these fields:
{
  "position": "U-slot e.g. U1, U3-U4, or Top",
  "equipment_type": "one of: Server, Network Switch, Patch Panel, KVM Switch, UPS, PDU, Storage, Rack Enclosure, Blank Panel, Cable Manager, Other",
  "brand": "manufacturer name e.g. Dell, HP, Cisco, APC",
  "model": "model name or best estimate with (est.)",
  "form_factor": "rack units e.g. 1U, 2U, 4U, 42U",
  "specifications": "key specs",
  "ports_interfaces": "visible ports",
  "max_ram": "",
  "storage_options": "",
  "confidence": "high, medium, or low",
  "notes": "any observations"
}

Start your response with [ and end with ]. No other text.`;

// Validate we have image data
const b64 = d.image_base64 || '';
const mediaType = d.media_type || d.image_type || 'image/jpeg';

if (!b64 || b64.length < 100) {
  throw new Error('No valid image base64 data received. Length: ' + b64.length);
}

return {
  body: JSON.stringify({
    model: 'claude-opus-4-6',
    max_tokens: 4096,
    messages: [{
      role: 'user',
      content: [
        {
          type: 'image',
          source: {
            type: 'base64',
            media_type: mediaType,
            data: b64
          }
        },
        { type: 'text', text: VISION_PROMPT }
      ]
    }]
  }),
  b64_length:    b64.length,
  image_url:     d.image_url     || '',
  output_format: d.output_format || 'json',
  request_id:    d.request_id    || ('req_' + Date.now()),
  timestamp:     d.timestamp     || new Date().toISOString()
};

// ─── Parse Vision Response & dcTrack Pre-mapping ─────────────────────────
const resp = $input.first().json;
let prev = {};
try { prev = $('🔨 Build Vision Prompt').first().json; } catch(e) {}

let text = '';
if (resp?.content?.[0]) text = resp.content[0].text || '';
else if (resp?.choices?.[0]) text = (resp.choices[0].message||{}).content || '';
else if (typeof resp === 'string') text = resp;

const cleaned = text.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();

let equipment = [];
if (cleaned.length > 0) {
  try {
    const p = JSON.parse(cleaned);
    equipment = Array.isArray(p) ? p : (p ? [p] : []);
  } catch(e1) {
    const m = cleaned.match(/\[[\s\S]*\]/);
    if (m) { try { equipment = JSON.parse(m[0]); } catch(e2) {} }
    if (equipment.length === 0) {
      const objs = cleaned.match(/\{[^{}]+\}/g);
      if (objs) objs.forEach(o => { try { equipment.push(JSON.parse(o)); } catch(e3) {} });
    }
  }
}

if (!Array.isArray(equipment) || equipment.length === 0) {
  equipment = [{ position:'U1', equipment_type:'Other', brand:'Unknown',
    model:'Vision parse failed', form_factor:'1U', confidence:'low' }];
}

const dcTrackClassMap = {
  'Server':'Device','Network Switch':'Network','Patch Panel':'Passive',
  'KVM Switch':'Network','UPS':'Device','PDU':'Rack PDU','Storage':'Device',
  'Rack Enclosure':'Cabinet','Blank Panel':'Passive','Cable Manager':'Passive','Other':'Device'
};

// Parse position string like "U3", "U3-U4", "U 5" → integer
const parseUPos = (posStr, fallback) => {
  if (!posStr) return fallback;
  const m = String(posStr).match(/U\s*(\d+)/i);
  return m ? parseInt(m[1], 10) : fallback;
};
const parseUHeight = (ff) => {
  if (!ff) return 1;
  const m = String(ff).match(/(\d+)\s*U/i);
  return m ? parseInt(m[1],10) : 1;
};

const enriched = equipment.map((item, idx) => {
  const s = item || {};
  return {
    ...s,
    dctrack_class:      dcTrackClassMap[s.equipment_type] || 'Device',
    dctrack_make:       s.brand  || '',
    dctrack_model:      s.model  || '',
    dctrack_u_height:   parseUHeight(s.form_factor),
    dctrack_u_position: parseUPos(s.position, idx + 1),  // ← parse "U3" properly
    dctrack_notes:      s.specifications || '',
    row_index:          idx
  };
});

return {
  equipment:             enriched,
  raw_vision_snippet:    text.slice(0, 300),
  image_url:             prev.image_url  || '',
  request_id:            prev.request_id || ('req_' + Date.now()),
  timestamp:             prev.timestamp  || new Date().toISOString(),
  total_equipment_found: enriched.length
};

