// Parse MCP dctrack_list_locations response
const resp = $input.first().json;
let prev = {};
try { prev = $('✅ Validate & Route Input').first().json; } catch(e) {}

let locations = [];
try {
  const data = resp.result || resp.data || resp;
  const arr = Array.isArray(data) ? data
             : Array.isArray(data.locations) ? data.locations
             : Array.isArray(data.items) ? data.items
             : [];

  // Filter to Rooms only using cmbHierarchyLevel
  // tiLocationCode already contains the full path e.g. "AI-DEMO-DC > AI-ROOM-01"
  const rooms = arr.filter(l => {
    const level = (l.cmbHierarchyLevel || '').toLowerCase();
    return level === 'room' || level === 'floor';
  });

  const source = rooms.length > 0 ? rooms : arr;

  locations = source.map(l => ({
    id:   l.id || '',
    name: l.tiLocationCode || l.tiLocationName || l.name || ''
  }));

} catch(e) {
  locations = [];
}

return {
  locations,
  request_id: prev.request_id || '',
  timestamp:  prev.timestamp  || new Date().toISOString()
};

