// ─── Build Cabinet Create Payload via MCP dctrack_create_item ────────────────
const d = $input.first().json;
const MCP_BASE = 'http://sunbird-mcp-server.iis-ai-ai.svc.cluster.local:8080';

const cabinetName  = (d.cabinet_name  || '').trim();
const locationName = (d.location_name || '').trim();
const uHeight      = parseInt(d.u_height || 42, 10);

if (!cabinetName)  throw new Error('cabinet_name is empty');
if (!locationName) throw new Error('location_name is empty');

// Use make/model from cabinet row in inventory if provided, else fallback to catalog default
function clean(s) {
  if (!s) return '';
  return s.replace(/\s*\(est\.?\)/gi,'').replace(/\s*\(approx\.?\)/gi,'')
          .replace(/\s*\(unknown\)/gi,'').replace(/\s*\?\s*$/g,'').trim();
}

const userMake  = clean(d.cabinet_make  || '');
const userModel = clean(d.cabinet_model || '');
const finalMake  = (userMake && userModel) ? userMake  : 'Rittal';
const finalModel = (userMake && userModel) ? userModel : 'VX5311.116';

console.log(`Cabinet: "${cabinetName}" | Make: "${finalMake}" | Model: "${finalModel}" | uHeight: ${uHeight}`);

return {
  toolUrl:  MCP_BASE + '/tools/dctrack_create_item',
  toolBody: {
    tiName:      cabinetName,
    tiClass:     'Cabinet',
    make:        finalMake,
    model:       finalModel,
    cmbLocation: locationName,
    tiRUs:       uHeight
  },
  cabinet_name:  cabinetName,
  location_name: locationName,
  u_height:      uHeight,
  inventory:     d.inventory  || [],
  request_id:    d.request_id || ('req_' + Date.now()),
  timestamp:     d.timestamp  || new Date().toISOString()
};

// ─── Aggregate Results ───────────────────────────────────────────────────────
const allResults = $input.all();

let buildPayload = {};
try { buildPayload = $('🏗️ Build Cabinet Payload').first().json || {}; } catch(e) {}

let parsedCab = {};
try { parsedCab = $('🏷️ Parse Cabinet Name').first().json || {}; } catch(e) {}

let cabinetId = null, cabinetError = null;
try {
  const r = ($('🗄️ MCP: Create Cabinet').first().json || {});
  const res = r.result || r;
  cabinetId = res.id || res.itemId || res.cid || null;
  if (r.error || r.message) cabinetError = JSON.stringify(r.error||r.message);
} catch(e) { cabinetError = e.message; }

function toStr(v){ return v==null?null:(typeof v==='string'?v:JSON.stringify(v)); }

const itemResults = allResults.map((item, i) => {
  const src  = (item||{})._json || (item||{}).json || {};
  const isOk = !!(
    src.item?.id || src.item?.tiID ||
    src.id || src.itemId || src.cid ||
    (src.result && (src.result.id || src.result.success)) ||
    (src._status && src._status < 400 && !src.errorList)
  );
  const usedFallback = src._usedFallback || false;
  const origMakeModel = usedFallback ? ` [fallback from ${src._originalMake}/${src._originalModel}]` : '';
  const err  = toStr(src.error)||toStr(src.message)||toStr(src.result&&src.result.error)||JSON.stringify(src).slice(0,300);
  return {
    index:       i+1,
    name:        src.itemLabel||(src.item?.tiName)||((src.toolBody||{}).name)||('Item '+(i+1)),
    class:       ((src.toolBody||{}).class)||'Device',
    cabinetSent: src.cabinetUsed || ((src.toolBody||{}).cabinet) || '?',
    status:      isOk ? 'created' : 'error',
    detail:      isOk ? null : err
  };
});

const ok  = itemResults.filter(r=>r.status==='created').length;
const err = itemResults.filter(r=>r.status==='error').length;

return [{
  success:              true,
  action:               'push_to_dctrack',
  cabinet_name:         buildPayload.cabinet_name||'',
  confirmed_cabinet:    parsedCab.confirmedCabinetName||buildPayload.cabinet_name||'',
  cabinet_sample:       parsedCab.cabinet_sample||[],
  list_cabinets_raw:    (parsedCab.list_cabinets_raw||'').slice(0,400),
  location_name:        buildPayload.location_name||'',
  cabinet_id:           cabinetId,
  cabinet_error:        cabinetError,
  items_created:        ok,
  items_errored:        err,
  item_results:         itemResults,
  request_id:           buildPayload.request_id||('req_'+Date.now()),
  completed_at:         new Date().toISOString()
}];

// ── Extract cabinet name from MCP dctrack_create_item response ───────────────
const buildPayload = $('🏗️ Build Cabinet Payload').first().json;
const cabinetResp  = $('🗄️ MCP: Create Cabinet').first().json;

const requestedName = buildPayload.cabinet_name || '';
const locationName  = buildPayload.location_name || '';

// dctrack_create_item returns { item: { tiName, ... } }
const createdName = (cabinetResp.item && cabinetResp.item.tiName)
                 || cabinetResp.tiName
                 || requestedName;

return {
  confirmedCabinetName: createdName,
  requestedName:        requestedName,
  locationName:         locationName,
  inventory:            buildPayload.inventory || [],
  u_height:             buildPayload.u_height,
  request_id:           buildPayload.request_id,
  timestamp:            buildPayload.timestamp
};

// Delete all existing items in the cabinet before re-creating
const elevData    = $('🧹 Get Existing Cabinet Items').first().json;
const parsedCab   = $('🏷️ Parse Cabinet Name').first().json;
const cabinetName = parsedCab.requestedName || parsedCab.confirmedCabinetName;
const MCP_BASE    = 'http://sunbird-mcp-server.iis-ai-ai.svc.cluster.local:8080';

// Flatten response — elevation API returns different shapes
const raw = elevData.items || elevData.data || elevData.result?.items
         || elevData.result?.data || elevData.result || [];
const existingItems = Array.isArray(raw) ? raw : [];

if (existingItems.length === 0) {
  console.log('Cabinet empty — no cleanup needed');
  return [{ deleted: 0, cabinetName }];
}

console.log(`Found ${existingItems.length} items to delete from ${cabinetName}`);

let deleted = 0;
let skipped = 0;

for (const item of existingItems) {
  const itemId = String(item.id || item.itemId || item.tiID || item.cid || '').trim();
  if (!itemId || itemId === 'undefined' || itemId === '0') {
    skipped++;
    continue;
  }

  try {
    const resp = await fetch(MCP_BASE + '/tools/dctrack_delete_item', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ itemId })
    });
    const txt = await resp.text();
    console.log(`Deleted item ${itemId}: ${resp.status}`);
    deleted++;
  } catch(e) {
    console.log(`Error deleting item ${itemId}: ${e.message}`);
    skipped++;
  }
}

console.log(`Done: deleted=${deleted} skipped=${skipped}`);
return [{ deleted, skipped, cabinetName }];

const d = $input.first().json;

if (d.is_upload) {
  return {
    image_base64:  d.image_base64,
    media_type:    d.image_type,
    image_url:     d.image_url,
    output_format: 'json',
    request_id:    d.request_id,
    timestamp:     d.timestamp
  };
}

throw new Error('URL-based image fetch not supported in this version. Please use the upload feature in the chat UI to send images directly.');

const parsed = $('🏷️ Parse Cabinet Name').first().json;
const inventory = parsed.inventory || [];

// Deduplicate by model name — model is the reliable field
const seen = new Set();
const searches = [];
for (const row of inventory) {
  const aiModel = (row.dctrack_model || row.model || '').trim();
  if (!aiModel || seen.has(aiModel.toLowerCase())) continue;
  seen.add(aiModel.toLowerCase());

  // Extract key search terms from model name (e.g. "PowerEdge C6100" -> "PowerEdge C6100")
  // Strip AI qualifiers
  const cleaned = aiModel.replace(/\s*\(est\.?\)/gi,'').replace(/\s*\(approx\.?\)/gi,'')
    .replace(/\s*\(unknown\)/gi,'').replace(/\s*\?\s*$/g,'').trim();

  searches.push({
    aiModel: aiModel,
    searchModel: cleaned,
    aiMake: '', // will be filled from first matching inventory row
  });
}

// Attach the AI make for reference
for (const s of searches) {
  const row = inventory.find(r => (r.dctrack_model||r.model||'').trim() === s.aiModel);
  if (row) s.aiMake = (row.dctrack_make || row.brand || '').trim();
}

console.log('Unique models to search:', searches.length, searches.map(s => s.searchModel));

// Output one item per unique model — HTTP node will iterate
return searches.map(s => ({
  ...s,
  _inventoryJson: JSON.stringify(inventory),
  _cabinetName: parsed.requestedName || parsed.confirmedCabinetName,
  _locationName: parsed.locationName || 'AI-DEMO-DC > AI-ROOM-01'
}));

// ═══ Match catalog results to inventory items & build dcTrack payloads ═══
const searchResults = $input.all();
const extractItems = $('🔎 Extract Unique Models').all();
const firstExtract = extractItems[0] ? extractItems[0].json : {};
const inventory = JSON.parse(firstExtract._inventoryJson || '[]');
const cabinetName = firstExtract._cabinetName || '';
const locationName = firstExtract._locationName || 'AI-DEMO-DC > AI-ROOM-01';
const MCP_BASE = 'http://sunbird-mcp-server.iis-ai-ai.svc.cluster.local:8080';

// ── Build model lookup: aiModel -> {make, model} from catalog ──
const modelLookup = {};  // key: aiModel.toLowerCase() -> {make, model, score, top5}

function fuzzy(a0, b0) {
  const a=(a0||'').toLowerCase().replace(/[^a-z0-9]/g,' ').replace(/\s+/g,' ').trim();
  const b=(b0||'').toLowerCase().replace(/[^a-z0-9]/g,' ').replace(/\s+/g,' ').trim();
  if(!a||!b) return 0; if(a===b) return 100; if(b.includes(a)) return 90; if(a.includes(b)) return 85;
  const tA=a.split(' ').filter(t=>t.length>1),tB=b.split(' ').filter(t=>t.length>1);
  let m=0;for(const ta of tA){if(tB.some(tb=>tb.includes(ta)||ta.includes(tb)))m++;}
  const ts=tA.length>0?(m/tA.length)*70:0;
  const nA=a.match(/\d{3,}/g)||[],nB=b.match(/\d{3,}/g)||[];
  let nb=0;for(const na of nA){if(nB.some(n=>n.includes(na)||na.includes(n)))nb+=20;}
  return Math.min(Math.round(ts+nb),99);
}

for (let i = 0; i < searchResults.length; i++) {
  const sr = searchResults[i].json;
  const ext = extractItems[i] ? extractItems[i].json : {};
  const catalog = (sr.result && sr.result.data) ? sr.result.data : (sr.result || []);
  const aiModel = (ext.aiModel || '').toLowerCase();
  const aiMake = ext.aiMake || '';

  console.log('Search "' + ext.searchModel + '": ' + catalog.length + ' catalog matches');

  if (!catalog.length) {
    modelLookup[aiModel] = { bestMake: null, bestModel: null, score: 0, top5: [] };
    continue;
  }

  // Score each catalog entry against the AI model name
  const scored = catalog.map(cm => ({
    make: cm.make || '',
    model: cm.model || '',
    cls: cm.class || '',
    score: fuzzy(ext.searchModel, cm.model || '')
  })).sort((a, b) => b.score - a.score);

  const top5 = scored.slice(0, 5);
  const best = top5[0];

  // The KEY insight: model name is reliable, so the best match's MAKE is the correct make
  // This auto-corrects "Cisco" -> "Cisco Systems" or any make name discrepancy
  console.log('  Best: make="' + best.make + '" model="' + best.model + '" score=' + best.score);
  console.log('  Top5: ' + top5.map(t => t.make + '/' + t.model + ':' + t.score).join(', '));

  modelLookup[aiModel] = {
    bestMake: best.score >= 40 ? best.make : null,
    bestModel: best.score >= 40 ? best.model : null,
    score: best.score,
    top5
  };
}

// ── Build dcTrack items ──
const classMap = {'Server':'Device','Network Switch':'Network','Switch':'Network','Patch Panel':'Data Panel','KVM Switch':'Network','UPS':'Device','PDU':'Rack PDU','Storage':'Device','Rack Enclosure':'Cabinet','Blank Panel':'Data Panel','Cable Manager':'Data Panel','Device':'Device','Network':'Network','Passive':'Data Panel','Data Panel':'Data Panel','Rack PDU':'Rack PDU','Other':'Device'};
const defaultModels = {'Cabinet':{make:'Rittal',model:'Orsted VX5311.116'},'Rack PDU':{make:'APC',model:'AP9320'},'Network':{make:'3Com',model:'Blade 3C13804'},'Device':{make:'3Com',model:'Gateway 3CRVO71330-06'},'Data Panel':{make:'Amp Netconnect',model:'1RU-AMP Panel RJ45 24-Port CAT6'}};

function clean(s){if(!s)return'';return s.replace(/\s*\(est\.?\)/gi,'').replace(/\s*\(approx\.?\)/gi,'').replace(/\s*\(unknown\)/gi,'').replace(/\s*\(generic\)/gi,'').replace(/\s*\(assumed\)/gi,'').replace(/\s*\?\s*$/g,'').trim();}

const used = new Set();
function nextFree(start,h){let p=Math.max(1,start);while(true){let ok=true;for(let i=0;i<h;i++){if(used.has(p+i)){ok=false;break;}}if(ok)return p;p++;}}
function reserve(p,h){for(let i=0;i<h;i++)used.add(p+i);}

const items = inventory.filter(row => {
  if (!row) return false;
  const c = (row.dctrack_class || row.equipment_type || '').toLowerCase();
  return c !== 'cabinet' && c !== 'rack enclosure';
}).map((row, idx) => {
  const itemClass = classMap[row.dctrack_class] || classMap[row.equipment_type] || 'Device';
  const def = defaultModels[itemClass] || defaultModels['Device'];
  const uH = Math.max(1, parseInt(row.dctrack_u_height, 10) || 1);
  const req = Math.max(1, parseInt(row.dctrack_u_position, 10) || (idx + 1));
  const uPos = nextFree(req, uH); reserve(uPos, uH);

  const userMake = clean(row.dctrack_make || row.brand || '');
  const userModel = clean(row.dctrack_model || row.model || '');

  // Model-first lookup: model name is reliable, so use catalog's make for that model
  const match = modelLookup[userModel.toLowerCase()] || {};
  let finalMake, finalModel;
  if (match.bestMake && match.bestModel) {
    // Catalog found a match — use catalog's make (auto-corrects user's make)
    finalMake = match.bestMake;
    finalModel = match.bestModel;
  } else {
    // No catalog match — fall back to defaults
    finalMake = def.make;
    finalModel = def.model;
  }

  console.log('  Item ' + idx + ': "' + userMake + '/' + userModel + '" -> "' + finalMake + '/' + finalModel + '" (score=' + (match.score||0) + ')');

  const equipType = (row.equipment_type || 'Item').toUpperCase().replace(/[^A-Z0-9 ]/g, '').trim();
  const nameBase = (userMake && userModel)
    ? cabinetName + ' ' + userMake.toUpperCase() + ' ' + userModel.replace(/[^A-Z0-9\-]/gi, '-').replace(/-+/g, '-').toUpperCase().slice(0, 20) + ' U' + uPos
    : cabinetName + ' ' + equipType + ' U' + uPos;

  const pduSide = (row.dctrack_pdu_position || '').trim();
  const isVPdu = (itemClass === 'Rack PDU' && pduSide !== '');
  const fUPos = isVPdu ? 0 : uPos;
  const pduX = isVPdu ? { mountedPduPosition: pduSide } : {};

  return {
    toolName: 'dctrack_create_item', toolUrl: MCP_BASE + '/tools/dctrack_create_item',
    toolBody: Object.assign({
      tiName: nameBase, tiClass: itemClass, make: finalMake, model: finalModel,
      cmbLocation: locationName, cabinetName: cabinetName, tiUPosition: fUPos
    }, pduX),
    itemLabel: nameBase, cabinetUsed: cabinetName, row_index: idx,
    matchScore: match.score || 0, matchTop5: (match.top5 || []).slice(0, 5)
  };
});

if (!items.length) return [{
